export function getUrgencyScore(condition, age, severity) {
  const base = { cardiac:95, stroke:98, fracture:60, fever:30, cough:20 };
  let score = base[condition?.toLowerCase()] || 50;
  if (age > 60) score += 10;
  if (severity > 3) score += 15;
  return Math.min(score, 100);
}
export function getUrgencyLevel(score) {
  if (score >= 80) return 'critical';
  if (score >= 50) return 'moderate';
  return 'low';
}

import { MultivariateLinearRegression } from 'ml-regression-multivariate-linear';
import PocketBase from 'pocketbase';
let model = null;
export async function trainLoadModel() {
  const pb = new PocketBase('http://127.0.0.1:8090');
  const records = await pb.collection('loadHistory').getFullList();
  if (!records.length) return;
  const X = records.map(r => [r.hour, r.dayOfWeek, r.queueLength]);
  const y = records.map(r => [r.waitTime, r.icuOccupancy]);
  model = new MultivariateLinearRegression(X, y);
}
export function predictLoad(hour, dayOfWeek, queueLength) {
  if (!model) return { waitTime: 0, icuOccupancy: 0 };
  const pred = model.predict([hour, dayOfWeek, queueLength]);
  return { waitTime: Math.round(pred[0]), icuOccupancy: Math.round(pred[1]) };
}

export function getSurgeLevel(icuOccupancy, erWait, admissionRate, movingAvg) {
  if (icuOccupancy > 85 || erWait > 45) return 'CRITICAL';
  if (admissionRate > movingAvg * 1.5) return 'WATCH';
  return 'STABLE';
}
export function computeMovingAverage(history, window=6) {
  const recent = history.slice(-window);
  return recent.reduce((a,b)=>a+b,0)/recent.length;
}

