// pages/UserPortal.jsx
import { useEffect, useState } from 'react';
import pb from '../lib/pocketbase';
import { getSurgeLevel } from '../lib/surgeLogic';
export default function UserPortal() {
  const [hospitals, setHospitals] = useState([]);
  const [surge, setSurge] = useState('STABLE');
  useEffect(() => {
    const fetch = async () => {
      const list = await pb.collection('hospitals').getFullList();
      setHospitals(list);
      const avgIcu = list.reduce((a,h)=>a+h.icuOccupancy,0)/list.length;
      const maxWait = Math.max(...list.map(h=>h.erWait));
      setSurge(getSurgeLevel(avgIcu, maxWait, 0, 0));
    };
    fetch();
    pb.collection('hospitals').subscribe('*', fetch);
    return () => pb.collection('hospitals').unsubscribe('*');
  }, []);
  return (
    <div className="p-4">
      <div className="flex justify-between">
        <h1 className="text-2xl font-bold">Emergency Routing</h1>
        <span className={`px-2 py-1 rounded text-white ${surge==='CRITICAL'?'bg-red-600':'bg-green-600'}`}>
          Surge Protocol: {surge}
        </span>
      </div>
      <button className="w-full bg-red-600 text-white py-4 rounded-lg my-4 text-xl">SOS</button>
      <h2 className="text-xl">Nearest Facilities</h2>
      {hospitals.map(h => (
        <div key={h.id} className="border p-2 my-2 rounded">
          <div className="font-bold">{h.name}</div>
          <div className={`badge ${h.status==='critical'?'bg-red-200':'bg-green-200'}`}>{h.status.toUpperCase()}</div>
          <div>ER Wait: {h.erWait} min + ICU: {h.icuOccupancy}%</div>
        </div>
      ))}
    </div>
  );
}

