import { useEffect, useState } from 'react';
import pb from '../lib/pocketbase';
import { getUrgencyLevel } from '../lib/urgencyModel';
export default function HospitalPortal() {
  const [patients, setPatients] = useState([]);
  useEffect(() => {
    const fetch = async () => {
